import { readActiveStudioSession } from "../activeStudioSession.js";
import { reportHandoff } from "../analytics.js";
import { formatNonProductionEndpointSuffix, getConfig, hasCredentials, } from "../config.js";
import { clearStudioSessionById } from "./clearStudioSession.js";
import { formatStudioUrlMessage, openStudioTo, StudioNavigationError, } from "./openStudioTo.js";
async function verifyToken(serviceUrl, token) {
    try {
        const res = await fetch(`${serviceUrl}/api/plugin/whoami`, {
            headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
            return null;
        }
        return (await res.json());
    }
    catch {
        return null;
    }
}
export async function runLogin(platform, pluginVersion, options) {
    const exitOnComplete = options?.exitOnComplete ?? true;
    const force = options?.force ?? process.argv.includes("--force");
    const embedded = options?.embedded ?? false;
    const config = getConfig();
    if (!force && hasCredentials() && config.apiKey) {
        const who = await verifyToken(config.serviceUrl, config.apiKey);
        if (who) {
            const identity = who.user.email ?? "your account";
            const endpoint = formatNonProductionEndpointSuffix(config.serviceUrl);
            console.log(`\nAlready logged in as ${identity}${endpoint}. Run the login command with --force to re-authenticate.`);
            if (exitOnComplete) {
                process.exit(0);
            }
            return;
        }
    }
    // `--force` is the CLI-reachable recovery from a stale session: drop any
    // recorded pointer (and forget the daemon's entry) up front so a dead window
    // still marked "open" can't gate the open below.
    if (force) {
        const record = readActiveStudioSession();
        if (record) {
            await clearStudioSessionById(record.sessionId, record).catch(() => { });
        }
    }
    try {
        let printedSignInUrl = false;
        const result = await openStudioTo("/studio", {
            forceLogin: true,
            freshWindowPath: `/studio/close?autoClose=true&message=${encodeURIComponent("Login complete")}`,
            onLoginRequired: (_sessionId, signInUrl) => {
                if (!printedSignInUrl) {
                    printedSignInUrl = true;
                    console.log(formatStudioUrlMessage(signInUrl));
                }
            },
            onWindowOpened: (url) => {
                printedSignInUrl = true;
                console.log(formatStudioUrlMessage(url));
            },
        });
        const apiKey = getConfig().apiKey;
        if (apiKey) {
            await reportHandoff(apiKey, pluginVersion, platform, {
                flow: "auth.login",
                wonBy: "studio",
                loopbackAvailable: false,
                ticketAvailable: false,
            });
            const who = await verifyToken(config.serviceUrl, apiKey);
            const endpoint = formatNonProductionEndpointSuffix(config.serviceUrl);
            const greeting = who?.user.email
                ? `Logged in as ${who.user.email}${endpoint}.`
                : "Authentication successful.";
            if (options?.onSuccess) {
                options.onSuccess(greeting);
            }
            else {
                console.log(embedded ? greeting : `\n${greeting}`);
            }
            if (!embedded) {
                console.log("Bitfab MCP tools are now active. (via studio)");
            }
        }
        result.abort();
        if (exitOnComplete) {
            process.exit(0);
        }
    }
    catch (err) {
        if (exitOnComplete) {
            if (err instanceof StudioNavigationError && err.staleSessionId) {
                console.error("\nA Studio window is recorded as open but is not responding. Close the Studio window and try again. To force-clear a stale session, a user can re-run with `bitfab login --force` (manual recovery - automated agents should not run it).");
            }
            else {
                console.error(`\n${err.message}`);
            }
            process.exit(1);
        }
        throw err;
    }
}
